import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";

const API_BASE = "http://localhost:5000";

const ProductDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [product, setProduct] = useState(null);
  const [related, setRelated] = useState([]);
  const [reviews, setReviews] = useState([]);

  const [loading, setLoading] = useState(true);
  const [qty, setQty] = useState(1);
  const [selectedImage, setSelectedImage] = useState("");
  const [activeTab, setActiveTab] = useState("description");

  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");

  useEffect(() => {
    window.scrollTo(0, 0);
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_BASE}/api/products/${id}`);
      const data = await res.json();

      if (data.success) {
        setProduct(data.product);
        setSelectedImage(data.product.images?.[0]);
      }

      const rv = await fetch(`${API_BASE}/api/reviews/${id}`);
      const rvData = await rv.json();
      if (rvData.success) setReviews(rvData.reviews);

      const rel = await fetch(`${API_BASE}/api/products/${id}/related`);
      const relData = await rel.json();
      if (relData.success) setRelated(relData.products);

    } catch (err) {
      console.log(err);
    }
    setLoading(false);
  };

  const addToCart = () => {
    const item = {
      _id: product._id,
      name: product.name,
      price: product.discountPrice || product.price,
      image: product.images?.[0],
      qty,
    };

    let cart = JSON.parse(localStorage.getItem("cart") || "[]");

    const exist = cart.find((x) => x._id === item._id);
    if (exist) exist.qty += qty;
    else cart.push(item);

    localStorage.setItem("cart", JSON.stringify(cart));
    alert("Đã thêm vào giỏ hàng!");
  };

  const buyNow = () => {
    addToCart();
    navigate("/cart");
  };

  if (loading) {
    return (
      <>
        <Header />
        <Navbar />
        <div className="text-center text-pink-600 mt-20 text-xl">
          Đang tải sản phẩm...
        </div>
      </>
    );
  }

  if (!product) {
    return (
      <>
        <Header />
        <Navbar />
        <div className="text-center text-red-600 mt-20 text-xl">
          Sản phẩm không tồn tại!
        </div>
      </>
    );
  }

  return (
    <>
      <Header />
      <Navbar />

      <div className="min-h-screen bg-[#fcecf2] py-12">
        <div className="max-w-7xl mx-auto px-4">

          {/* --------- KHUNG CHÍNH --------- */}
          <div className="bg-white rounded-3xl shadow-xl p-10 grid grid-cols-1 md:grid-cols-2 gap-10">

            {/* Ảnh sản phẩm */}
            <div>
              <div className="rounded-3xl overflow-hidden border border-pink-200 bg-pink-50">
                <img
                  src={API_BASE + selectedImage}
                  className="w-full h-[450px] object-cover"
                  alt=""
                />
              </div>

              {/* Ảnh nhỏ */}
              <div className="flex gap-3 mt-4">
                {product.images?.map((img, i) => (
                  <img
                    key={i}
                    src={API_BASE + img}
                    className={`w-20 h-20 rounded-xl object-cover border cursor-pointer ${
                      selectedImage === img
                        ? "border-pink-500"
                        : "border-pink-200"
                    }`}
                    onClick={() => setSelectedImage(img)}
                    alt=""
                  />
                ))}
              </div>
            </div>

            {/* ----------- INFO ----------- */}
            <div>
              <h1 className="text-4xl font-bold text-[#4b2c35]">{product.name}</h1>

              <div className="mt-3 flex items-center gap-4">
                <span className="text-3xl text-pink-600 font-bold">
                  {(product.discountPrice || product.price).toLocaleString()}₫
                </span>

                {product.discountPrice && (
                  <span className="line-through text-gray-500">
                    {product.price.toLocaleString()}₫
                  </span>
                )}
              </div>

              <p className="text-gray-600 mt-2">
                Đã bán: <b>{product.sold || 0}</b> — Còn:{" "}
                <b>{product.stock || 0}</b>
              </p>

              {/* Số lượng */}
              <div className="mt-6">
                <h3 className="font-semibold mb-2 text-gray-700">Số lượng</h3>
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => setQty(Math.max(1, qty - 1))}
                    className="w-9 h-9 border rounded-full bg-pink-100 text-lg"
                  >
                    -
                  </button>

                  <span className="text-xl">{qty}</span>

                  <button
                    onClick={() => setQty(qty + 1)}
                    className="w-9 h-9 border rounded-full bg-pink-100 text-lg"
                  >
                    +
                  </button>
                </div>
              </div>

              {/* Nút */}
              <div className="flex gap-5 mt-8">
                <button
                  onClick={addToCart}
                  className="px-8 py-3 bg-pink-500 text-white rounded-full shadow-lg hover:bg-pink-600"
                >
                  Thêm vào giỏ
                </button>

                <button
                  onClick={buyNow}
                  className="px-8 py-3 border border-pink-500 text-pink-600 rounded-full hover:bg-pink-50"
                >
                  Mua ngay
                </button>
              </div>
            </div>
          </div>

          {/* --------- TABS --------- */}
          <div className="bg-white mt-12 rounded-3xl shadow-xl p-8">
            <div className="flex gap-8 border-b">
              <button
                onClick={() => setActiveTab("description")}
                className={`pb-3 ${
                  activeTab === "description"
                    ? "border-b-2 border-pink-500 text-pink-600"
                    : "text-gray-600"
                }`}
              >
                Mô tả
              </button>

              <button
                onClick={() => setActiveTab("reviews")}
                className={`pb-3 ${
                  activeTab === "reviews"
                    ? "border-b-2 border-pink-500 text-pink-600"
                    : "text-gray-600"
                }`}
              >
                Đánh giá ({reviews.length})
              </button>
            </div>

            {/* CONTENT */}
            <div className="mt-5">
              {activeTab === "description" && (
                <p className="text-gray-700 leading-relaxed whitespace-pre-line">
                  {product.description}
                </p>
              )}

              {activeTab === "reviews" && (
                <div>
                  {reviews.length === 0 ? (
                    <p className="text-gray-500">Chưa có đánh giá nào.</p>
                  ) : (
                    <div className="space-y-4 max-h-80 overflow-y-auto">
                      {reviews.map((rv, index) => (
                        <div
                          key={index}
                          className="bg-pink-50 p-4 rounded-xl border border-pink-100"
                        >
                          <b className="text-[#4b2c35]">{rv.name}</b>
                          <div className="text-yellow-500">
                            {"★".repeat(rv.rating)}
                            <span className="text-gray-300">
                              {"★".repeat(5 - rv.rating)}
                            </span>
                          </div>
                          <p className="text-gray-700 mt-1">{rv.comment}</p>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>

          {/* --------- RELATED PRODUCTS --------- */}
          {related.length > 0 && (
            <div className="mt-14">
              <h2 className="text-2xl font-bold text-[#4b2c35] mb-4">
                Sản phẩm liên quan
              </h2>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {related.map((p) => (
                  <div
                    key={p._id}
                    onClick={() => navigate(`/product/${p._id}`)}
                    className="bg-white rounded-2xl shadow p-3 cursor-pointer hover:-translate-y-1 duration-200"
                  >
                    <img
                      src={API_BASE + p.images[0]}
                      className="h-40 w-full object-cover rounded-xl"
                      alt=""
                    />
                    <p className="mt-2 font-semibold text-[#4b2c35]">
                      {p.name}
                    </p>
                    <p className="text-pink-600 font-bold">
                      {(p.discountPrice || p.price).toLocaleString()}₫
                    </p>
                  </div>
                ))}
              </div>
            </div>
          )}

        </div>
      </div>

      <Footer />
    </>
  );
};

export default ProductDetail;
